            "F4SE",
            include_str!("../ui/f4se_tab.slint"),
        ),
        (
            "ui/scanner_tab.slint",
            "ScannerTab",
            "Scanner",
            include_str!("../ui/scanner_tab.slint"),
        ),
        (
            "ui/tools_tab.slint",
            "ToolsTab",
            "Tools",
            include_str!("../ui/tools_tab.slint"),
        ),
        (
            "ui/settings_tab.slint",
            "SettingsTab",
            "Settings",
            SETTINGS_SLINT,
        ),
        (
            "ui/about_tab.slint",
            "AboutTab",
            "About",
            include_str!("../ui/about_tab.slint"),
